import React from 'react';
import ToDoFormAdd from './ToDoFormAdd';
import Filters from './Filters';
import Item from './Item';
import Modal from '../modal/Modal';

const items = [
    {
        id: 1,
        title: "Learn HTML",
        done: true
    },

    {
        id: 2,
        title: "Learn CSS",
        done: true
    },

    {
        id: 3,
        title: "Learn JS",
        done: true
    },

    {
        id: 4,
        title: "Learn React",
        done: true
    }
]

const ToDoList = () => {
    const addTask = (value) => {
            alert(value);
        }

    return (
        <div className='container-todo'>
            <h1>ToDo List</h1>

            <ToDoFormAdd addTask={addTask}/>

            <div className='todo'>
                <Filters />

                <div className="list">
                    { items.map(item => <Item item={item} key={item.id}/>)}
                </div>
            </div>

            <Modal visible = {true}/>
        </div>
    );
}

export default ToDoList;
